// Auth Guard — Pass-through for trusted Flask backend calls
// Flask backend is the only caller; no API key validation needed here
const items = $input.all();
return items;

// Extract Files — Validate binary file is present from multipart upload
const itemsOut = [];

for (const item of items) {
  if (item.binary && item.binary.file) {
    itemsOut.push(item);
  } else if (item.binary) {
    // Try any binary key (n8n may use 'data' or other keys)
    const keys = Object.keys(item.binary);
    if (keys.length > 0) {
      // Rename first binary key to 'file' for downstream compatibility
      const firstKey = keys[0];
      item.binary.file = item.binary[firstKey];
      itemsOut.push(item);
    } else {
      throw new Error('No file received in binary data');
    }
  } else {
    throw new Error('No file received in binary.file');
  }
}

return itemsOut;

// Pipeline 1: Data Processing
// Clean text, detect sections, prepare for scoring
const items = $input.all();
const results = [];

for (const item of items) {
  const rawText = item.json.data || item.json.text || '';

  // Clean text
  const cleanText = rawText
    .replace(/\r\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .replace(/[^\x20-\x7E\n]/g, ' ')
    .trim();

  // Detect sections for quality check
  const sections = [];
  const sectionPatterns = {
    education: /education|academic|degree|university/i,
    experience: /experience|employment|work history/i,
    skills: /skills|technical|competencies/i,
    projects: /projects|portfolio/i,
    summary: /summary|objective|profile/i
  };

  for (const [name, pattern] of Object.entries(sectionPatterns)) {
    if (pattern.test(cleanText)) sections.push(name);
  }

  // Carry forward body fields from webhook
  const bodyData = items[0]?.json?.body || {};

  results.push({
    json: {
      file_name: item.json.file_name || item.binary?.file?.fileName || 'resume.pdf',
      resume_text: cleanText,
      word_count: cleanText.split(/\s+/).length,
      sections_detected: sections,
      section_count: sections.length,
      job_description: bodyData.job_description || item.json.job_description || 'Software Engineer with relevant skills',
      role: bodyData.role || item.json.role || 'Software Engineer',
      top_n: parseInt(bodyData.top_n || item.json.top_n) || 5,
      pipeline_stage: 'P1_complete'
    }
  });
}

return results;

// Attach scoring result back to resume metadata
const scoreData = $input.first().json;
return [{
  json: {
    file_name: scoreData.file_name || 'unknown',
    ats_score: scoreData.ats_score || 0,
    agent_score: scoreData.agent_score || 0,
    confidence: scoreData.confidence || 'low',
    reasoning: scoreData.reasoning || '',
    evidence: scoreData.evidence || [],
    matched_skills: scoreData.matched_skills || [],
    missing_skills: scoreData.missing_skills || [],
    thought_trace: scoreData.thought_trace || [],
    pipeline_stage: 'P2_complete'
  }
}];

// Rank & Shortlist — Sort by hybrid score, apply top_n
const items = $input.all();
const topN = items[0]?.json?.top_n || items.length;

const candidates = items.map((item, i) => {
  const d = item.json;
  return {
    rank: 0,
    file_name: d.file_name || `candidate_${i+1}`,
    ats_score: d.ats_score || 0,
    agent_score: d.agent_score || 0,
    hybrid_score: Math.round((d.ats_score || 0) * 0.4 + (d.agent_score || 0) * 10 * 0.6),
    confidence: d.confidence || 'low',
    reasoning: d.reasoning || '',
    evidence: d.evidence || [],
    matched_skills: d.matched_skills || [],
    missing_skills: d.missing_skills || []
  };
});

candidates.sort((a, b) => b.hybrid_score - a.hybrid_score);
const shortlisted = candidates.slice(0, topN).map((c, i) => ({
  ...c, rank: i + 1, shortlisted: true
}));

return shortlisted.map(c => ({ json: c }));

// Build Final Response
const items = $input.all();
const candidates = items.map(item => item.json);

return [{
  json: {
    status: 'success',
    processed: {
      total_processed: candidates.length,
      shortlisted: candidates.filter(c => c.shortlisted).length,
      candidates: candidates,
      pipeline: {
        stage_1: 'data_processing (n8n)',
        stage_2: 'intelligence (Flask API)',
        orchestrator: 'n8n',
        models_used: ['gemini-2.5-flash', 'gemini-2.5-flash-lite', 'groq-llama-3.3'],
        timestamp: new Date().toISOString()
      }
    }
  }
}];

// Per-Resume Error Handler — don't crash entire pipeline
const error = $input.first().json;
return [{
  json: {
    file_name: error.file_name || 'unknown',
    ats_score: 0,
    agent_score: 0,
    confidence: 'low',
    reasoning: 'Processing failed for this resume',
    error: error.message || 'Unknown error',
    pipeline_stage: 'P2_error'
  }
}];

// Global Error Handler
return [{
  json: {
    success: false,
    error: $input.first().json.message || 'Pipeline processing failed',
    timestamp: new Date().toISOString()
  }
}];
